{"file_path":"/home/user/workspace/lib/catalog.js","content":"import { unstable_cache } from 'next/cache';
import { getAllProducts } from '@/lib/db';

/**
 * Returns product catalog data, cached with the "products" cache tag.
 *
 * Every cached reader that depends on this tag stays in sync: calling
 * revalidateTag("products") anywhere (e.g. from a sync action) causes
 * the next request to any tagged consumer to re-fetch fresh data.
 */
export const getCachedProducts = unstable_cache(
  async () => getAllProducts(),
  ['catalog-products-list'],
  { tags: ['products'] },
);
"}

